sql:
SELECT MAX(problem_count) AS max_problem_count
FROM (
  SELECT COUNT(problem_id) AS problem_count
  FROM problems
  GROUP BY difficulty
);

external_knowledge:
- 'revered challenges' refers to problems with the highest average scores;
- 'accolades bestowed upon them by the solvers' refers to the scores given by users;
- 'domains' refers to the categories and difficulty levels of the problems.

sql:
SELECT AVG(success_rate) AS average_success_rate
FROM problems
WHERE category = 'caching';

SELECT COUNT(submission_id) AS total_submissions_for_problem_0
FROM submissions
WHERE problem_id = 0;

